var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중. 교전 속행 가능.</color>","JPN":"<color=#ff3636>損傷部位を修理中。交戦続行可能。</color>","ENG":"<color=#ff3636>Repairing damage. Ready to engage.</color>","TWN":"<color=#ff3636>正在維修損壞部位，可以繼續交戰。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_26"},{"id":"L5_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>적성 개체를 섬멸합니다.</color>","JPN":"<color=#ff3636>敵性個体を殲滅します。</color>","ENG":"<color=#ff3636>Eliminating hostile entity.</color>","TWN":"<color=#ff3636>殲滅敵人個體。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제길, 뭐 저딴 게 다 있어……!","JPN":"くそ、化け物かよ……！","ENG":"Damn it, what even is this thing...?!","TWN":"該死，怎麼會有那種東西！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"특수탄을 이렇게나 때려 박았는데, 꿈쩍도 안 하잖아!","JPN":"特殊弾をあれほどぶち込んだのに、びくともしない！","ENG":"I pumped it full of special bullets and it didn't even flinch!","TWN":"打了這麼多特殊彈，居然一點反應都沒有！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"깡통 로봇 주제에 더럽게 단단하네……!","JPN":"ボロ缶ロボットのくせに硬すぎだろ……！","ENG":"For a tin can robot, it's ridiculously tough...!","TWN":"這破鐵桶機器人居然這麼硬！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"하우스홀드 네트워크 갱신…….","JPN":"ハウスホールドネットワーク更新……","ENG":"Household Network updated...","TWN":"家用網路更新……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L13_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"대 침식 4종 섬멸 병기, 모더레이터로군요.","JPN":"対侵食第4種殲滅兵器、モデレーターですね。","ENG":"That's the Moderator, the Anti-Corruption annihilator designed for defeating Category 4 C.O.s.","TWN":"是對抗侵蝕4類殲滅兵器，仲裁者。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"개발 목적은 어떠한 조건에서도 작전 수행이 가능하도록 만들어진 병기.","JPN":"どのような条件下でも作戦遂行を可能にすることを開発目的として作られた兵器。","ENG":"It was developed to operate under any condition, no matter the environment.","TWN":"開發目的是為了在任何條件下都能執行作戰任務的兵器。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"아마도 생체 강철 시스템을 통해, 자가 회복이 가능한 모양입니다.","JPN":"おそらく生体鋼鉄システムを通じ、自己回復も可能かと。","ENG":"Looks like it's equipped with a bio-steel system that lets it self-repair.","TWN":"可能是通過生物鋼鐵系統，實現了自我恢復的功能。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"4종 섬멸 병기라고?","JPN":"第4種殲滅兵器だと？","ENG":"An annihilator designed for defeating Category 4 C.O.s?","TWN":"4類殲滅武器？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 저 커다란 깡통 로봇이 4종 침식체 수준이란 말이야?","JPN":"じゃあ、あのデカいボロ缶ロボットが第4種侵食体レベルってこと？","ENG":"You're telling me that giant robot is as dangerous as a Category 4 C.O.?","TWN":"那麼，那台巨大的鐵罐機器人是4類侵蝕體級別的嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그렇습니다, 라이카.","JPN":"そのとおりです、ライカ。","ENG":"That's correct, Laika.","TWN":"是的，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"유효 타개책은 CRF에 의한 직접 공격으로 코어 부분을 파괴하는 것.","JPN":"有効な打開策はCRFによる直接攻撃でコアを破壊すること。","ENG":"The only viable option is using CRF to directly strike and destroy its core.","TWN":"有效的解決方案是通過CRF的直接攻擊來摧毀核心部分。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, CRF라고? 우리 중엔 카운터가 없잖아?","JPN":"くそ、CRFだと？　こっちにはカウンターがいないってのに！","ENG":"Damn it, did you just say CRF? But we don't even have a Counter with us!","TWN":"喂，CRF？我們之間可沒有制裁者啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"결국, 어떻게든 지근거리에서 코어에 이터니움 특수탄을 때려박는 수밖에 없나?","JPN":"結局、なんとかして至近距離でコアにエタニウム特殊弾をぶち込むしかないのか？","ENG":"So the only way is to get in close and shove some Eternium bullets into the core?","TWN":"最終，看來只能在近距離用永恆之金特殊彈打擊核心了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"역시 안 되겠어요, 라이카.","JPN":"やっぱりダメです、ライカ。","ENG":"That won't work, Laika.","TWN":"果然不行啊，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 비켜요, <color=#ffd34c>망원경</color>을 쓸게요!","JPN":"みんなどいてください、<color=#ffd34c>望遠鏡</color>を使います！","ENG":"Everyone get back, I'll use the <color=#ffd34c>Telescope</color>!","TWN":"大家讓開，我要用<color=#ffd34c>望遠鏡</color>了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그거라면 어떻게든 여길 돌파할 수 있겠지……!","JPN":"これならなんとかここを突破できるはず……！","ENG":"That should be enough to break through...!","TWN":"那樣的話，總可以突破這裡吧…！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"기다려, 허접 꼬맹아!","JPN":"待ちなさい、ヘタクソガキ！","ENG":"Hold it, you scrawny brat!","TWN":"等等，臭小鬼！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"너희들이 도착할 곳은 통신조차 닿지 않는 고심도 이면세계야.","JPN":"あんたたちの行き先は、通信すら届かない高深度裏世界。","ENG":"Where you're headed is the hyperdepths of the Counterside that even comms can't reach.","TWN":"你們要去的地方是連通訊都沒有的高深度異界。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"망원경은 그곳에서 너희에게 길을 알려줄 유일한 이정표 같은 거라고!","JPN":"望遠鏡はそこであんたたちを案内してくれる唯一の道しるべなのよ！","ENG":"The Telescope is the only guide you'll have once you're in there!","TWN":"望遠鏡是唯一能在那裡為你們指引道路的路標！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그곳에서 무슨 일이 발생할지 모르는데, 여기서 그걸 낭비할 수는 없어!","JPN":"何があるかもわからないのに、ここでそれを無駄遣いするわけにはいかない！","ENG":"You don't know what you'll run into, so you can't afford to waste it now!","TWN":"不知道在那裡會發生什麼事？，所以不能在這裡浪費！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그렇지만 저건 4종 침식체와 맞먹는 병기잖아요!","JPN":"でもあれは第4種侵食体並みの兵器なんでしょう！","ENG":"But that thing's on par with a Category 4 C.O.!","TWN":"可是那是相當於4類侵蝕體的兵器啊！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 라면, 타이밍을 맞추지 못할 수도 있다고요!","JPN":"このままだと、間に合わないかもしれません！","ENG":"If we screw up the timing here, we're toast!","TWN":"照這樣下去，可能會失去好時機！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"That's why–","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"엇!?","JPN":"あっ！？","ENG":"Huh?!","TWN":"咦！？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L41_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장! 그쪽으로 간다!","JPN":"くそ！　そっちに行くぞ！","ENG":"Damn it! It's headed your way!","TWN":"該死！到那邊去了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"피해, 꼬맹이……!","JPN":"危ない、おこちゃま……！","ENG":"Watch out, kid...!","TWN":"快躲開，小鬼！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>새로운 유기체 감지. 바이탈 체크 실행.</color>","JPN":"<color=#ff3636>新しい有機体感知。バイタルチェック実行。</color>","ENG":"<color=#ff3636>New organic beings detected. Checking vital signs.</color>","TWN":"<color=#ff3636>發現新的有機體，執行生命體征確認。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_26"},{"id":"L48_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>적성 개체를 섬멸합니다.</color>","JPN":"<color=#ff3636>敵性個体を殲滅します。</color>","ENG":"<color=#ff3636>Eliminating hostile entity.</color>","TWN":"<color=#ff3636>殲滅敵人個體。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough* *Cough...!*","TWN":"咳咳，咳咳！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"괜찮아, 꼬맹이. 안 다쳤어?","JPN":"大丈夫か、おこちゃま？　怪我はない？","ENG":"You okay, kid? Are you hurt?","TWN":"沒事吧，小鬼。沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"네, 고마워요. 라이카는 괜찮아요?","JPN":"うん、ありがとう。ライカは？","ENG":"No I'm not. Thanks, Laika. What about you?","TWN":"嗯，謝謝你，萊卡沒事吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"괜찮아. 살짝 스쳤을 뿐이니까.","JPN":"大丈夫。かすっただけだ。","ENG":"I'm fine. Just a graze.","TWN":"沒關係。只是輕輕擦傷而已。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"큭큭, 근데 어째 포지션이 바뀌니까 기분이 묘하다?","JPN":"くくっ、でもなんだかポジションが変わるって妙な気分だな。","ENG":"Hehe, it's funny how different it feels when our roles are flipped.","TWN":"呵呵，不過位置換了，感覺有點奇妙呢？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"돌이켜보면, 평소에는 네가 나를 지켜준 적이 훨씬 더 많았는데 말이야.","JPN":"振り返ってみると、いつもは守られることの方がずっと多かったのに。","ENG":"Thinking back, you've been the one protecting me more often than not.","TWN":"回想起來，平時都是你保護我更多呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러게요. 이번에는 반대네요.","JPN":"そうね。今回は反対ね。","ENG":"Yeah. But it's the other way around this time.","TWN":"是啊，這次相反呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어쨌든 나한테 맡기라고. 내가 어떻게든 꼬맹이 널 지켜 보일 테니까……!","JPN":"とにかく、私に任せな。なんとしてでもおこちゃま、あんたを守って見せるから……！","ENG":"Anyway, leave it to me. I'll keep you safe no matter what...!","TWN":"總之交給我吧。我會想辦法保護你這個小鬼的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"틀렸습니다, 라이카.","JPN":"いいえ、ライカ。","ENG":"That won't be necessary, Laika.","TWN":"錯了，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"여기서는 저희가 길을 열어드리죠.","JPN":"ここは私たちが道を開きましょう。","ENG":"We'll open a path for you.","TWN":"在這裡，我們會為你開路。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 무슨 뾰족한 방법이라도 있는 거야?","JPN":"なんだよ、いい方法でもあるのか？","ENG":"Wait, what? You got some kind of trick up your sleeve?","TWN":"什麼？你有什麼有效的辦法嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"시뮬레이션 예측 결과. 펠리세트의 망원경을 제외하면…….","JPN":"シミュレーション予測結果、フェリセットの望遠鏡を除けば……","ENG":"According to our simulations, excluding Félicette's Telescope...","TWN":"模擬預測結果。除了費莉塞特的望遠鏡……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"이 중, 모더레이터를 쓰러트릴 수 있는 화력을 가진 사람은 라이카밖에 없습니다.","JPN":"この中で、モデレーターを倒せるような火力を持っているのはライカしかいません。","ENG":"You're the only one among us with the firepower to destroy the Moderator, Laika.","TWN":"在這些人中，唯一能擊敗仲裁者的火力只有萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그것도 매우 한정적인 조건에서만 가능하죠.","JPN":"それも極めて限定的な条件下でのみ可能です。","ENG":"And even then, only under very specific conditions.","TWN":"那也只能在非常有限的條件下實現。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"한정적인 조건이라고……?","JPN":"限定的な条件……？","ENG":"Specific conditions...?","TWN":"有限的條件?"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그리고 저희가 그 한정적인 조건을 달성해 드리겠습니다.","JPN":"私たちがその限定的な条件を達成してさしあげます。","ENG":"We'll make sure those conditions are met.","TWN":"而我們將為你達成那些有限的條件。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"지정 사수, 저격 포인트를 확보했습니다.","JPN":"指定射手、狙撃ポイントを確保。","ENG":"Sniper locked in position.","TWN":"指定射手，已佔領狙擊點。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"ROSE_BETA_MAID_ON","text":{"KOREA":"위치에서 대기 중.","JPN":"位置にて待機中。","ENG":"Awaiting the shot.","TWN":"在位置待命中。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"저격이라고? 그렇다면……?","JPN":"狙撃だと？　ってことは……？","ENG":"Sniper? Then that means...","TWN":"狙擊？那麼……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"깜빡이를 켜겠습니다, 라이카.","JPN":"ウィンカーを出します、ライカ。","ENG":"Turning on the blinker, Laika.","TWN":"我要打方向燈了，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"모더레이터의 공격 대상이 바뀐 순간이 기회입니다.","JPN":"モデレーターの攻撃対象が移った瞬間がチャンスです。","ENG":"When the Moderator switches targets, that's your chance.","TWN":"仲裁者的攻擊目標改變的瞬間就是機會。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 잠깐만……!","JPN":"おい、待てよ……！","ENG":"Hey, wait a sec...!","TWN":"喂，等一下！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"무슨 짓을 하려는 거야, 메이드……!","JPN":"何をするつもりだ、メイド……！","ENG":"What are you trying to do, maid...?!","TWN":"你想幹什麼？女僕！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>새로운 유기체 감지.</color>","JPN":"<color=#ff3636>新しい有機体感知。</color>","ENG":"<color=#ff3636>New organic beings detected.</color>","TWN":"<color=#ff3636>發現新的有機體。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_26"},{"id":"L41_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>대인 살상 용도로 주무장을 교체합니다.</color>","JPN":"<color=#ff3636>対人殺傷用途に主武装を交替します。</color>","ENG":"<color=#ff3636>Changing to anti-personnel weapon loadout.</color>","TWN":"<color=#ff3636>更換用於對人殺傷的主武裝。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야, 메이드…!!","JPN":"おい、メイド……！！","ENG":"Hey, maid...!!","TWN":"啊，女僕！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"너, 지금 일부러 공격 유도를……?","JPN":"あんた、今わざと攻撃を……？","ENG":"You're drawing its fire on purpose...?","TWN":"你，現在是故意引導攻擊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"데이터… 아카이브 완료…….","JPN":"データ……アーカイブ完了……","ENG":"Data... archived...","TWN":"資料……存檔完成……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"지정 사수… 저격하세요……!","JPN":"指定射手……狙撃せよ……！","ENG":"Sniper... take the shot...!","TWN":"指定射手……狙擊……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L7_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>심각한 손상 확인.</color>","JPN":"<color=#ff3636>深刻な損傷を確認。</color>","ENG":"<color=#ff3636>Critical damage detected.</color>","TWN":"<color=#ff3636>確認嚴重損傷。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_03"},{"id":"L8_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중.</color>","JPN":"<color=#ff3636>損傷部位を修理中。</color>","ENG":"<color=#ff3636>Repairing damage.</color>","TWN":"<color=#ff3636>正在維修損壞部位。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"한정적 조건, 달성 완료.","JPN":"限定的な条件、達成完了。","ENG":"The specified conditions have been fulfilled.","TWN":"限定條件，達成完畢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"지금입니다, 라이카.","JPN":"今です、ライカ。","ENG":"Now's your chance, Laika.","TWN":"就是現在，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"모더레이터의 다리가 파괴된 지금이라면, 노출된 코어에 접근할 수 있겠죠.","JPN":"モデレーターの足が破壊された今なら、露出されたコアに接近できるはずです。","ENG":"With the Moderator's legs destroyed, you should be able to reach the exposed core.","TWN":"仲裁者的腿部被破壞了，現在可以接近暴露的核心了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"무슨 소리야? 저 녀석 피가 많이 나잖아!","JPN":"何言ってるんだ？　あいつ出血がひどいぞ！","ENG":"What are you talking about? She's bleeding like crazy!","TWN":"你在說什麼？那傢伙流了很多血！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"저대로 지혈 안 하면 죽는다고!","JPN":"あのまま止血しないと死ぬ！","ENG":"She's gonna die if we don't stop the bleeding!","TWN":"不趕快止血的話會死的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"네. 이미 상정된 결과입니다. 무슨 문제라도?","JPN":"はい。すでに想定済みの結果です。何か問題でも？","ENG":"Yes. That outcome was already accounted for. Is there a problem?","TWN":"是的。這是已經預料到的結果。有問題嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"메이드란, 마스터께서 바라는 뜻을 이루는 삶의 형태.","JPN":"メイドとは、マスターの望みを叶える生き方をする者。","ENG":"A maid is someone who serves her master to do their bidding.","TWN":"女僕就是要追隨主人一生，按照主人的意願而活的人。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"마스터께서는 당신들을 반드시 살리라고 명령하셨습니다.","JPN":"マスターは必ずあなたたちを生還させるようお命じになりました。","ENG":"Master ordered us to keep you alive, no matter what.","TWN":"主人命令我一定要救你們。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그 변태 할망구가……?","JPN":"あの変態ババァが……？","ENG":"That perverted hag...?","TWN":"那個變態瘋婆子？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"그리고 네트워크로 사고를 공유하는 저희에게 개별 개체로서의 죽음은 무의미.","JPN":"それにネットワークで思考を共有している私たちに、個体としての死は無意味です。","ENG":"And since our thoughts are shared through the Network, individual deaths have no meaning to us.","TWN":"而且對於通過網路共用思維的我們來說，作為個體的死亡是毫無意義的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"왜냐하면 꽃은 시들거나, 꺾이면 언제든 대체될 수 있는 존재니까요.","JPN":"花は枯れたり折れたりしても、いつでも代わりがきく存在ですから。","ENG":"After all, a flower that withers or breaks can always be replaced.","TWN":"因為花朵總是可以被替代的，無論是枯萎還是被折斷。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"즉, 이 상황에서 BR-175의 희생은 가장 합리적인 코스트입니다.","JPN":"つまり、この状況でBR-175の犠牲は最も合理的なコストです。","ENG":"In other words, BR-175's sacrifice is the most rational cost in this situation.","TWN":"也就是說，在這種情況下，BR-175的犧牲是最合理的代價。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"합리적인 코스트? 지금 장난해……!?","JPN":"合理的なコスト？　冗談じゃねえぞお前！","ENG":"Rational cost? Are you kidding me...?!","TWN":"合理的代價？你在開玩笑吧！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"장난? 이건 장난이 아닙니다, 라이카.","JPN":"もちろん、これは冗談ではありません、ライカ。","ENG":"Kidding? I'm not joking, Laika.","TWN":"開玩笑？這可不是玩笑，萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"지금 기회를 놓치면, 더 많은 코스트를 부담하게 되겠죠.","JPN":"今このチャンスを逃せば、より多くのコストを負担することになるでしょう。","ENG":"If we miss this chance, the cost will only grow.","TWN":"如果現在錯過這個機會，就會承擔更多的成本吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"UI_FIERCE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>쿠드라프카, 들려?</color>","JPN":"<color=#ff3636>クドリャフカ、聞こえる？</color>","ENG":"<color=#ff3636>Kudryavka, do you hear me?</color>","TWN":"<color=#ff3636>庫德里亞夫卡，聽得到嗎？</color>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>죽기 싫으면 즉시, 탐사선을 돌려!</color>","JPN":"<color=#ff3636>死にたくないなら今すぐ、探査船の舵を切れ！</color>","ENG":"<color=#ff3636>If you don't want to die, turn that scout ship around now!</color>","TWN":"<color=#ff3636>不想死的話，立刻把探測船調回來！？/color>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇지만… 명령이… 그리고 대원들은……!","JPN":"でも……命令が……それに隊員たちが……！","ENG":"But... my orders... and the others...!","TWN":"但是……命令……還有隊員們…！"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>장난해? 어차피 다른 녀석들은 늦었어!</color>","JPN":"<color=#ff3636>何を言っている。どうせ他のやつらはもう手遅れだ！</color>","ENG":"<color=#ff3636>Are you stupid!? They're all already gone!</color>","TWN":"<color=#ff3636>開玩笑嗎？反正其他傢伙已經遲到了！/color>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>지금 기회를 놓치면, 녀석들에게 전부 격추될 거야!</color>","JPN":"<color=#ff3636>今このチャンスを逃せば、やつらに全部撃墜されてしまう！</color>","ENG":"<color=#ff3636>If you hesitate now, you'll be shot down with them!</color>","TWN":"<color=#ff3636>如果現在錯過機會，就會被那些傢伙全部擊落！/color>"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이런 개 같은……!","JPN":"ちくしょう……！","ENG":"You've got to be kidding me...!","TWN":"你這個混蛋……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제기랄, 하면 되잖아, 하면……!!","JPN":"やればいいんだろ、やれば……！！","ENG":"Damn it, fine! I'll do it...!!","TWN":"該死，我做就是了，行了吧……！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L45_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중.</color>","JPN":"<color=#ff3636>損傷部位を修理中。</color>","ENG":"<color=#ff3636>Repairing damage.</color>","TWN":"<color=#ff3636>正在維修損壞部位。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L48_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"드디어 머리를 잡았네!","JPN":"やっと頭を掴んだ！","ENG":"Got your head at last!","TWN":"終於逮到要害了！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이 끈질긴 딱정 벌레 자식……!","JPN":"このしつこいカブトムシ野郎……！","ENG":"You stubborn little beetle...!","TWN":"你這個臭甲蟲！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이거나 쳐먹고, 얌전히 뒈져버리라고!!","JPN":"これでも食らって、大人しくくたばれ！","ENG":"Eat this and stay down for good!!","TWN":"吃我一招，乖乖去死吧！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이 빌어먹을 자식아아아……!!","JPN":"このクソ野郎がああ……！！","ENG":"You miserable piece of junk...!!","TWN":"你這個該死的傢伙啊啊啊……！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"적성 개체 완전 섬멸.","JPN":"適性個体、完全殲滅。","ENG":"No more hostile responses.","TWN":"敵人個體完全殲滅。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"수고하셨습니다, 메이드 라이카.","JPN":"お疲れ様でした、メイドライカ。","ENG":"Well done, Maid Laika.","TWN":"辛苦了，女僕萊卡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"하아… 하아… 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff...* *Huff...* *Huff...!*","TWN":"哈啊……哈啊……哈啊！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"시끄러워, 누가 메이드라고……!","JPN":"うるさい、誰がメイドだ……！","ENG":"Shut it. Who are you calling a maid...?!","TWN":"吵死了，誰說我是女僕！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"괴, 굉장해요, 라이카…!","JPN":"す、すごいわ、ライカ……！","ENG":"Th-that was amazing, Laika...!","TWN":"真，真厲害，萊卡！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"순식간에 모더레이터의 머리에 올라타서 코어를 날려버리더니……!","JPN":"あっという間にモデレーターの頭に乗っかってコアを飛ばしちゃうなんて……！","ENG":"You climbed right onto the Moderator's head and blew up the core like it was nothing...!","TWN":"瞬間跳到仲裁者的頭上，把核心打飛了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"어떻게 한 거예요? 꼭 카운터 같았어요.","JPN":"どうやったの？　まるでカウンターみたいだった。","ENG":"How'd you do it? You looked just like a real Counter.","TWN":"你是怎麼做到的？看起來就像是制裁者。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"설마 지금까지 실력을 숨기고 있던 거예요?","JPN":"まさか、今まで実力を隠してたの？","ENG":"Have you've been hiding your true power this whole time?","TWN":"難道你一直在隱藏實力嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그럴 리가 없잖냐? 솔직한 게 내 유일한 장점이라고.","JPN":"そんなわけないだろ？　正直なところが私の唯一の長所だっつーの。","ENG":"Yeah right. Being honest is, like, my only redeeming trait.","TWN":"怎麼可能？誠實是我唯一的優點。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"가자, 꼬맹이.","JPN":"行こう、おこちゃま。","ENG":"Let's go, kid.","TWN":"走吧，小鬼。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이런 데서 꾸물댈 시간 없으니까.","JPN":"こんなところでグズグズしてる暇なんてない。","ENG":"We don't have time to stand around here.","TWN":"沒時間在這裡磨蹭。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"목표 포인트에 도착했습니다.","JPN":"目標ポイントに到着しました。","ENG":"We've reached the objective point.","TWN":"到達目標點。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"ROSE_BETA_MAID_OFF","text":{"KOREA":"블랙 로즈 분대 전원, 싱글 다이브가 준비되는 동안 위치를 사수합니다.","JPN":"ブラックローズ全分隊員、シングルダイブの準備が整うまで位置を死守します。","ENG":"All Black Rose units will hold position while the single dive is prepared.","TWN":"黑玫瑰小隊全員，請在單人躍入準備期間堅守位置。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSE_BETA_MAID_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"좋아, 이쪽은 준비됐어요, 박사님!","JPN":"よし、こちらは準備オッケーです、博士！","ENG":"All right, we're ready on this end, Doctor!","TWN":"好的，這邊準備好了，博士！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"싱글 다이브인지 뭔지, 한 번 구경이나 해 보자고, 쥐돌이.","JPN":"やってやろうじゃないか、そのシングルダイブってやつ。","ENG":"Let's see what this single dive thing's all about, rat-girl.","TWN":"來看看什麼是單人躍入吧，老鼠。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"기다려, 지금 좌표를 역산하고 있으니까…….","JPN":"待って、今座標を逆算してるから……","ENG":"Hold on, I'm reverse-calculating the coordinates...","TWN":"等一下，我正在反向計算座標……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"좌표 역산 완료……!","JPN":"座標逆算完了……！","ENG":"Coordinates reverse-calculated...!","TWN":"座標反向計算完成……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야, 꼬맹이 뭔가 웃기지 않냐?","JPN":"おい、おこちゃま。なんだか笑えないか？","ENG":"Hey, kid. Doesn't this feel kinda stupid to you?","TWN":"喂，小鬼，有什麼好笑的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐가요, 라이카?","JPN":"何が笑えるの、ライカ？","ENG":"What do you mean, Laika?","TWN":"什麼，萊卡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"지난번에는 밤하늘에 빛나는 별에 닿을 것처럼 하늘로 치솟았는데 말이지.","JPN":"この前は夜空に光る星に届くくらい空高く飛んだのに。","ENG":"Last time, we blasted off like we were about to grab the stars.","TWN":"上次就像要觸碰到夜空中閃耀的星星一樣衝向天空。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이번에는 멀쩡한 맨땅에다 다이빙하게 생겼잖냐? 대체 우리 인생은 왜 이런 거냐?","JPN":"今度は地面にダイブするんだろ？　私たちの人生っていったいどうなってるんだ？","ENG":"This time, we're face-planting into a pile of dirt. Why are our lives so messed up?","TWN":"這次又要在平地上躍入？我們的生活到底為什麼是這樣？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하핫, 그건 그러네요.","JPN":"ははっ、それもそうね。","ENG":"Haha, I guess so when you put it that way.","TWN":"啊哈哈，確實如此呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 저는 후회 안 해요. 라이카는 후회해요?","JPN":"でも、後悔はしてないわ。ライカは後悔してる？","ENG":"But I don't regret any of it. What about you, Laika?","TWN":"但是我不後悔。萊卡，你後悔嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"후회는 개뿔이. 이 꼴로 여기까지 왔는데 포기할 것 같아?","JPN":"するわけない。この様でここまで来たのに、諦めてたまるものか。","ENG":"Heck no. We've come this far looking like clowns. You think I'm gonna quit now?","TWN":"後悔個頭。我都這樣走到這一步了，你覺得我會放棄嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"가자, 가서 그 녀석을 데리고 오자고!","JPN":"行こう、行ってあいつを連れて来よう！","ENG":"Let's go. We're bringing her back home!","TWN":"走吧，去把那她帶回來！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"물론이에요, 라이카!","JPN":"もちろんよ、ライカ！","ENG":"Absolutely, Laika!","TWN":"當然囉，萊卡！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"차원 항로 설정 완료! 외장 아스트라 드라이브 세트 온……!","JPN":"次元航路設定完了！　外装アストラ・ドライブセットオン……！","ENG":"Dimensional route set! External Astra Drive, online...!","TWN":"次元航路設定完成！啟動艾斯特拉引置……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"싱글 다이브, 레디!","JPN":"シングルダイブ、レディー！","ENG":"Single dive, ready!","TWN":"單人躍入，準備！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"아 맞다. 둘 다 다이브 멀미는 안하지?","JPN":"あ、そうだ。2人とも、ダイブ酔いはしないよね？","ENG":"Oh, right. Neither of you get dive-sick, right?","TWN":"啊，對了。你們兩個都不會暈吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다, 다이브 멀미라고요……!","JPN":"だ、ダイブ酔い……！？","ENG":"D-dive-sick...?!","TWN":"躍入暈眩……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야! 쥐돌이! 너 왜 그런 걸 이제 와서……!","JPN":"おい！　なんでそれを今言うんだよ、ネズミ野郎！","ENG":"Rat-girl! Why are you just telling us about that...?!","TWN":"喂！老鼠！？為什麼現在才……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"꽤 어지러울 거야. 참으라고……!","JPN":"かなり目眩がするけど、我慢しなさい……！","ENG":"It's gonna get real dizzy. Suck it up...!","TWN":"會有點暈的。忍住！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그럼, 행운을 빈다, 개와 고양이!","JPN":"じゃあ、幸運を祈るわ、犬と猫！","ENG":"Well then, good luck, dog and cat!","TWN":"那就祝你們好運吧，小貓和小狗！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"보고 계십니까요, 전대장님?","JPN":"見てるでやんすか？　戦隊長。","ENG":"Are you watching, Commander?","TWN":"你看到了嗎？隊長？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"지난 20년이라는 시간…….","JPN":"20年という時間……","ENG":"It's been twenty years...","TWN":"過去的20年時間……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그리고 이 퓨처 앳 워 항공 우주 연구소의 모든 예산…….","JPN":"そしてこのフューチャーアットウォー航空宇宙研究所の全ての予算……","ENG":"And the entire budget of Future-at-War's Aerospace Research Lab...","TWN":"還有這天啟兵器航空航太研究所的所有預算……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"이번에야 말로… 변명의 여지없이 시간과 예산은 충분했습니다요…….","JPN":"今度こそ……言い訳の余地もなく、時間と予算は十分だったでやんす……","ENG":"This time... we had the time and budget. No excuses...","TWN":"這次……毫無藉口，時間和預算都很充足……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"앰버 박사가 퓨처 앳 워를 떠난 뒤로도 제가 이곳을 지켰던 이유는…….","JPN":"アンバー博士がフューチャーアットウォーを後にしてからも、私がここに残った理由は……","ENG":"The reason why I stayed here even after Dr. Amber left Future-at-War is...","TWN":"安柏博士離開天啟兵器後，我仍然守護在這裡的原因……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"어쩌면 지금 이 순간을 위해서 일지도 모릅니다요.","JPN":"もしかしから、今この瞬間のためだったのかもしれないでやんす。","ENG":"Maybe for this very moment.","TWN":"或許就是為了這一刻。"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"왠지 또 이런 역할을 떠맡아 버린 것 같지만…….","JPN":"なぜかまたこんな役割を担当することになっちゃったでやんすが……","ENG":"Feels like I've gotten myself roped into another one of these roles again, but...","TWN":"總覺得又被迫承擔了這樣的角色……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"이번에야 말로…….","JPN":"今度こそ……","ENG":"But this time, I hope...","TWN":"這次……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"당신의 유지를 이은, 저 애송이들이 성공할 수 있기를…….","JPN":"あなたの遺志を受け継いだ、あの子たちが成功しますように……","ENG":"That those kids will carry on your legacy...","TWN":"希望那些繼承你遺志的小鬼們能夠成功……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"역경을 넘어서, 부디 별에 닿을 수 있기를…….","JPN":"逆境を乗り越えて、どうか星に届くよう……","ENG":"I hope they make it past all the trials and touch the stars...","TWN":"願他們能跨越逆境，觸及星辰……"},"stage":{"bg":"YAKSHA_05","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"저는 여기서 기도하겠습니다요.","JPN":"私はここで祈るでやんす。","ENG":"That's what I'll be praying for right here.","TWN":"我將在這裡祈禱。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"……전대장님.","JPN":"……戦隊長。","ENG":"...Commander.","TWN":"……戰隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};